package com.treeeducation.ioas.system.operatorprofile;
import jakarta.persistence.*;import java.time.Instant;
/** Operator profile used by lead/task assignment and dropdowns. */
@Entity @Table(name="operator_profile") public class OperatorProfile{ @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private Long userId; @Column(nullable=false,length=80) private String name; @Column(length=40) private String phone; @Column(length=80) private String teamName; @Column(nullable=false) private Boolean enabled=true; @Column(nullable=false) private Instant createdAt=Instant.now(); public Long getId(){return id;} public void setId(Long id){this.id=id;} public Long getUserId(){return userId;} public void setUserId(Long userId){this.userId=userId;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getPhone(){return phone;} public void setPhone(String phone){this.phone=phone;} public String getTeamName(){return teamName;} public void setTeamName(String teamName){this.teamName=teamName;} public Boolean getEnabled(){return enabled;} public void setEnabled(Boolean enabled){this.enabled=enabled;} public Instant getCreatedAt(){return createdAt;} public void setCreatedAt(Instant createdAt){this.createdAt=createdAt;} }
